/// <summary>
/// This is an controller class for report VolumeFromCustomers
/// </summary>
internal final class ETGVolumeFromCustomersController extends SrsReportRunController
{
}

Method.Source:
public static ETGVolumeFromCustomersController construct()
{
    return new ETGVolumeFromCustomersController();

}

/// <summary>
/// Class entry point. The system will call this method when a designated menu
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
    ETGVolumeFromCustomersController controller =  ETGVolumeFromCustomersController::construct();

    controller.parmReportName(ssrsReportStr(ETGVolumeFromCustomersReport, Report));
    controller.parmArgs(_args);
    controller.parmLoadFromSysLastValue(false);
    controller.startOperation();
}
